import React, { useState, useEffect } from 'react';
import axios from 'axios';
import speciesOptions from '../data/speciesData';
import { jwtDecode } from 'jwt-decode';
import { useNavigate } from 'react-router-dom';

function KhaiBaoCoSo() {
  const navigate = useNavigate();

  const initialFormState = {
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    loaiHinhCoSo: '', ngayThanhLap: '', giayPhepKinhDoanh: '',
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '',
    loaiCoSoDangKy: '',
    tenLamSan: [], // sửa từ string thành mảng
    tenKhoaHoc: [], // sửa từ string thành mảng
    issueDate: '', expiryDate: '',
    trangThai: 'Đang hoạt động', ghiChu: ''
  };

  const [formData, setFormData] = useState(initialFormState);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  useEffect(() => {
    const token = localStorage.getItem('token');
    if (!token) return navigate('/login');
    try {
      const decoded = jwtDecode(token);
      if (!decoded || !decoded.role) throw new Error('Invalid token');
    } catch (err) {
      localStorage.removeItem('token');
      navigate('/login');
    }
  }, [navigate]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleMultiSpeciesChange = (e) => {
    const selected = Array.from(e.target.selectedOptions).map(opt => opt.value);
    const khoaHocList = selected.map(name => {
      const found = speciesOptions.find(s => s.name === name);
      return found?.scientificName || '';
    });
    setFormData(prev => ({
      ...prev,
      tenLamSan: selected,
      tenKhoaHoc: khoaHocList
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    const token = localStorage.getItem('token');
    try {
      const res = await axios.post('http://localhost:10000/api/farms', formData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setMessage({ type: 'success', text: 'Đăng ký thành công!' });
      setFormData(initialFormState);
    } catch (err) {
      setMessage({ type: 'error', text: 'Lỗi khi gửi dữ liệu.' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '20px' }}>
      <h2>Đăng ký cơ sở gây nuôi</h2>

      {message.text && (
        <div style={{ color: message.type === 'error' ? 'red' : 'green' }}>
          {message.text}
        </div>
      )}

      <form onSubmit={handleSubmit}>
        <div>
          <label>Tên cơ sở:</label>
          <input type="text" name="tenCoSo" value={formData.tenCoSo} onChange={handleChange} required />
        </div>

        <div>
          <label>Loại cơ sở đăng ký:</label>
          <select name="loaiCoSoDangKy" value={formData.loaiCoSoDangKy} onChange={handleChange} required>
            <option value="">-- Chọn loại --</option>
            <option value="Đăng ký cơ sở gây nuôi">Cơ sở gây nuôi</option>
            <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Cơ sở gỗ</option>
          </select>
        </div>

        {formData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
          <>
            <div>
              <label>Loài nuôi (chọn nhiều):</label>
              <select multiple value={formData.tenLamSan} onChange={handleMultiSpeciesChange}>
                {speciesOptions.map((s, i) => (
                  <option key={i} value={s.name}>{s.name}</option>
                ))}
              </select>
            </div>

            <div>
              <label>Tên khoa học:</label>
              <textarea
                readOnly
                disabled
                value={formData.tenKhoaHoc.join('\n')}
                rows={formData.tenKhoaHoc.length || 1}
              />
            </div>
          </>
        )}

        <div>
          <label>Trạng thái:</label>
          <select name="trangThai" value={formData.trangThai} onChange={handleChange}>
            <option value="Đang hoạt động">Đang hoạt động</option>
            <option value="Tạm dừng">Tạm dừng</option>
            <option value="Đã đóng cửa">Đã đóng cửa</option>
          </select>
        </div>

        <button type="submit" disabled={loading}>
          {loading ? 'Đang gửi...' : 'Đăng ký'}
        </button>
      </form>
    </div>
  );
}

export default KhaiBaoCoSo;
